class Solution:
    def findMin(self, nums: List[int]) -> int:
        left = 0
        right = len(nums) - 1
        test = len(nums) - 1

        while left <= right:
            mid = (left + right) // 2

            if mid + 1 >= len(nums):
                return nums[mid + 1]
            elif nums[mid] > nums[mid + 1]:
                return nums[mid + 1]
            elif nums[mid] > nums[test]:
                left = mid + 1
            else:
                right = mid - 1

        return nums[0]

